import { supabase } from '../lib/supabase'
import type { TrainingPlan, TrainingPlanInsert, TrainingPlanUpdate } from '../types/database'

export async function getTrainingPlans(userId?: string): Promise<TrainingPlan[]> {
  let query = supabase.from('training_plans').select('*').order('created_at', { ascending: false })

  if (userId) {
    query = query.eq('user_id', userId)
  }

  const { data, error } = await query

  if (error) throw error
  return data ?? []
}

export async function getTrainingPlan(id: number, userId?: string): Promise<TrainingPlan | null> {
  let query = supabase.from('training_plans').select('*').eq('id', id)

  if (userId) {
    query = query.eq('user_id', userId)
  }

  const { data, error } = await query.single()

  if (error) throw error
  return data
}

export async function createTrainingPlan(plan: TrainingPlanInsert): Promise<TrainingPlan> {
  const { data, error } = await supabase.from('training_plans').insert(plan).select().single()

  if (error) throw error
  return data
}

export async function updateTrainingPlan(
  id: number,
  plan: TrainingPlanUpdate
): Promise<TrainingPlan> {
  const { data, error } = await supabase
    .from('training_plans')
    .update({ ...plan, updated_at: new Date().toISOString() })
    .eq('id', id)
    .select()
    .single()

  if (error) throw error
  return data
}

export async function deleteTrainingPlan(id: number): Promise<void> {
  const { error } = await supabase.from('training_plans').delete().eq('id', id)

  if (error) throw error
}
